// Import the necessary classes and libraries
import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;

// This class extends AppCompatActivity and represents the main activity of an Android app
public class MainActivity extends AppCompatActivity {

    // Declare a private variable for binding the layout with this activity
    private ActivityMainBinding binding;

    // This method is called when the activity is first created
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Inflate the layout and set it as the content view for this activity
        binding = ActivityMainBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        // Load a URL in the web view in the layout
        binding.webView.loadUrl("https://sites.google.com/view/d4rk7355608/home");
    }
}

import android.os.Build;
import android.webkit.WebSettings;

WebSettings settings = binding.webView.getSettings();
settings.setJavaScriptEnabled(false); // keep disabled unless strictly required
settings.setDomStorageEnabled(true);
settings.setAllowFileAccess(false);
settings.setAllowContentAccess(false);
settings.setSupportZoom(false);

if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
    settings.setSafeBrowsingEnabled(true);
}
if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
    settings.setMixedContentMode(WebSettings.MIXED_CONTENT_NEVER_ALLOW);
}

import android.net.Uri
import android.webkit.WebResourceRequest
import android.webkit.WebView
import android.webkit.WebViewClient

private val trustedHosts = setOf("developer.android.com", "example.com")

binding.webView.webViewClient = object : WebViewClient() {
    override fun shouldOverrideUrlLoading(view: WebView, request: WebResourceRequest): Boolean {
        val uri: Uri = request.url
        val isTrusted = uri.scheme == "https" && uri.host in trustedHosts
        return !isTrusted // true blocks untrusted navigation
    }
}

import android.net.Uri;
import android.webkit.WebResourceRequest;
import android.webkit.WebView;
import android.webkit.WebViewClient;
import java.util.Set;

Set<String> trustedHosts = Set.of("developer.android.com", "example.com");

binding.webView.setWebViewClient(new WebViewClient() {
    @Override
    public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
        Uri uri = request.getUrl();
        boolean isTrusted = "https".equals(uri.getScheme()) && trustedHosts.contains(uri.getHost());
        return !isTrusted; // true blocks untrusted navigation
    }
});
